	.TITLE	T	.PROC	M680002	.REF	LIB	.REF	DRIVERS; Flags pour D2 dans DRTRANCHE; ----------------------------BDRTDD	=	16		; dessine la droite DdBDRTDA	=	17		; dessine la droite DaBDRT12	=	18		; dessine dans les cadrants I et IIBDRT34	=	19		; dessine dans les cadrants III et IVBDRTEX	=	20		; dessine juste les surfaces extrieuresBDRTFA	=	21		; dessine la faceBDRTDV	=	22		; dessine la droite verticale	.LOC	0OBUDIS:	.BLKB	100LGVAR:	.LOC	0START:	LOAD.L	A6,#R16"VAR	LOAD.W	D0,#0	LOAD.W	D1,#60	CLR.L	D2	TSET.L	D2:#BDRTEX	LOAD.W	D3,#150	SWAP.W	D3	LOAD.W	D3,#400	LOAD.W	D4,#30	SWAP.W	D4	LOAD.W	D4,#100	LOAD.W	D5,#4020$:	LOAD.W	D2,#SETDOT	CALL	DRPTRANCHE	PUSH.L	D3	.W	LIB,?GETCAR	POP.L	D3	LOAD.W	D2,#CLRDOT	CALL	DRPTRANCHE	ADD.W	D0,#45	ADD.W	D1,#45	COMP.W	D0,#360	JUMP,LO 20$	EXIT;-----------\\; DRPTRANCHE >;===========/; Dessine une tranche de gteau paisse.; in	D0.W	angle de dpart (0..360);	D1.W	angle d'arrive (0..360);	D2.W	mode + flags (BDRT..);	D3.L	centre (y;x);	D4.L	rayons (ry;rx);	D5.W	paisseur; out	-; mod	D7.WDRPTRANCHE:	PUSHM.L	D0..D6.W LIB,?BUCAR	CALL	DRPTRFD	CALL	DRPTRFA	PUSH.L	D3	SWAP.W	D3	ADD.W	D3,D5	SWAP.W	D3	TCLR.L	D2:#BDRTDD	TCLR.L	D2:#BDRTDA	TSET.L	D2:#BDRT12	TCLR.L	D2:#BDRT34	CALL	DRTRANCHE	POP.L	D3; Dessine la droite verticale au centre.	TEST.L	D2:#BDRTEX	JUMP',BS 30$	COMP.W	D0,#90	JUMP',HS 22$	COMP.W	D1,#90	JUMP',HS 30$22$:	COMP.W	D0,#360+90	JUMP',HS 30$	COMP.W	D1,#360+90	JUMP',HS 30$24$:	PUSHM.L	D3,D4	LOAD.W	D4,D5	INC.W	D4	SWAP.W	D4	CLR.W	D4	CALL	DRLINE		; dessine la ligne Vc	POPM.L	D3,D4; Dessine la droite verticale  gauche.30$:	COMP.W	D0,#180	JUMP',HS 32$	COMP.W	D1,#180	JUMP',HS 34$32$:	COMP.W	D0,#360+180	JUMP',HS 40$	COMP.W	D1,#360+180	JUMP',LO 40$34$:	PUSHM.L	D3,D4	SUB.W	D3,D4	LOAD.W	D4,D5	INC.W	D4	SWAP.W	D4	CLR.W	D4	CALL	DRLINE		; dessine la droite Vl	TEST.L	D2:#BDRTEX	JUMP',BC 38$	INC.W	D3	SWAP.W	D3	SWAP.W	D4	ASR.W	D4,#1	SUB.W	D3,D4	SWAP.W	D3	CALL	DRFILL38$:	POPM.L	D3,D4; Dessine la droite verticale  droite.40$:	COMP.W	D0,#0	JUMP',HS 42$	COMP.W	D1,#0	JUMP',HS 44$42$:	COMP.W	D0,#360+0	JUMP',HS 50$	COMP.W	D1,#360+0	JUMP',LO 50$44$:	PUSHM.L	D3,D4	ADD.W	D3,D4	LOAD.W	D4,D5	INC.W	D4	SWAP.W	D4	CLR.W	D4	CALL	DRLINE		; dessine la droite Vr	TEST.L	D2:#BDRTEX	JUMP',BC 48$	DEC.W	D3	SWAP.W	D3	SWAP.W	D4	ASR.W	D4,#1	SUB.W	D3,D4	SWAP.W	D3	CALL	DRFILL48$:	POPM.L	D3,D4; Dessine la face suprieure.50$:	TSET.L	D2:#BDRTDD	TSET.L	D2:#BDRTDA	TSET.L	D2:#BDRT12	TSET.L	D2:#BDRT34	TEST.L	D2:#BDRTEX	JUMP',BC 60$	TCLR.L	D2:#BDRTDD	TCLR.L	D2:#BDRTDA;	TSET.L	D2:#BDRT12	TCLR.L	D2:#BDRT3460$:	CALL	DRTRANCHE.W LIB,?NOBUCAR	POPM.L	D0..D6	RET;--------\\; DRPTRFD >;--------/; Dessine la face de dpart.; in	D0.W	angle de dpart (0..360);	D1.W	angle d'arrive (0..360);	D2.W	mode + flags (BDRT..);	D3.L	centre (y;x);	D4.L	rayons (ry;rx);	D5.W	paisseur; out	-; mod	D7.WDRPTRFD:	PUSHM.L	D0..D5	SWAP.W	D3	ADD.W	D3,D5	SWAP.W	D3	COMP.W	D0,#270	JUMP',HS 24$	COMP.W	D0,#180	JUMP',HS 23$	COMP.W	D0,#90	JUMP',HS 22$21$:				; dans cadrant I =>	TCLR.L	D2:#BDRTFA	TSET.L	D2:#BDRTDV	JUMP'	30$22$:				; dans cadrant II =>	TSET.L	D2:#BDRTFA	TSET.L	D2:#BDRTDV	JUMP'	30$23$:				; dans cadrant III =>	TEST.L	D2:#BDRTEX	JUMP,BS 90$	TSET.L	D2:#BDRTFA	TSET.L	D2:#BDRTDV	JUMP'	30$24$:				; dans cadrant IV =>	TEST.L	D2:#BDRTEX	JUMP,BS 90$	TCLR.L	D2:#BDRTFA	TCLR.L	D2:#BDRTDV;	JUMP'	30$30$:	TEST.L	D2:#BDRTDV	JUMP',BC 50$	PUSHM.L	D3,D4	PUSH.L	D5	CALL	PCERCLE	LOAD.L	D3,D5	POP.L	D5	LOAD.W	D4,D5	NEG.W	D4	SWAP.W	D4	CLR.W	D4	CALL	DRLINE		; dessine la ligne Vd	TEST.L	D2:#BDRTEX	JUMP',BC 40$	DEC.W	D3	SWAP.W	D3	SWAP.W	D4	ASR.W	D4,#1	SUB.W	D3,D4	SWAP.W	D3	CALL	DRFILL40$:	POPM.L	D3,D450$:	TEST.L	D2:#BDRTEX	JUMP',BS 90$	TEST.L	D2:#BDRTFA	JUMP',BC 90$	PUSH.L	D5	CALL	PCERCLE	LOAD.L	D4,D5	POP.L	D5;;?	CALL	DRPTRFI	SUB.W	D4,D3		; D4 <-- dx	SWAP.W	D4	SWAP.W	D3	SUB.W	D4,D3		; D4 <-- dy	SWAP.W	D4	SWAP.W	D3	CALL	DRLINE		; dessine la droite Fd90$:	POPM.L	D0..D5	RET;--------\\; DRPTRFA >;--------/; Dessine la face d'arrive.; in	D0.W	angle de dpart (0..360);	D1.W	angle d'arrive (0..360);	D2.W	mode + flags (BDRT..);	D3.L	centre (y;x);	D4.L	rayons (ry;rx);	D5.W	paisseur; out	-; mod	D7.WDRPTRFA:	PUSHM.L	D0..D5	CLR.L	D0	LOAD.W	D0,D1		; D0 <-- angle d'arrive	DIV.WU	D0,#360	SWAP.W	D0	SWAP.W	D3	ADD.W	D3,D5	SWAP.W	D3	COMP.W	D0,#270	JUMP',HS 24$	COMP.W	D0,#180	JUMP',HS 23$	COMP.W	D0,#90	JUMP',HS 22$21$:				; dans cadrant I =>	TSET.L	D2:#BDRTFA	TSET.L	D2:#BDRTDV	JUMP'	30$22$:				; dans cadrant II =>	TCLR.L	D2:#BDRTFA	TSET.L	D2:#BDRTDV	JUMP'	30$23$:				; dans cadrant III =>	TEST.L	D2:#BDRTEX	JUMP,BS 90$	TCLR.L	D2:#BDRTFA	TCLR.L	D2:#BDRTDV	JUMP'	30$24$:				; dans cadrant IV =>	TEST.L	D2:#BDRTEX	JUMP,BS 90$	TSET.L	D2:#BDRTFA	TSET.L	D2:#BDRTDV;	JUMP'	30$30$:	TEST.L	D2:#BDRTDV	JUMP',BC 50$	PUSHM.L	D3,D4	PUSH.L	D5	CALL	PCERCLE	LOAD.L	D3,D5	POP.L	D5	LOAD.W	D4,D5	NEG.W	D4	SWAP.W	D4	CLR.W	D4	CALL	DRLINE		; dessine la ligne Va	TEST.L	D2:#BDRTEX	JUMP',BC 40$	INC.W	D3	SWAP.W	D3	SWAP.W	D4	ASR.W	D4,#1	SUB.W	D3,D4	SWAP.W	D3	CALL	DRFILL40$:	POPM.L	D3,D450$:	TEST.L	D2:#BDRTEX	JUMP',BS 90$	TEST.L	D2:#BDRTFA	JUMP',BC 90$	PUSH.L	D5	CALL	PCERCLE	LOAD.L	D4,D5	POP.L	D5;;?	CALL	DRPTRFI	SUB.W	D4,D3		; D4 <-- dx	SWAP.W	D4	SWAP.W	D3	SUB.W	D4,D3		; D4 <-- dy	SWAP.W	D4	SWAP.W	D3	CALL	DRLINE		; dessine la droite Fa90$:	POPM.L	D0..D5	RET;--------\\; DRPTRFI >;--------/     ; Cache une face intrieure (paralllogramme).; in	D3.L	centre (y;x);	D4.L	point (y;x);	D5.W	hauteur; out	-; mod	D7.WDRPTRFI:	PUSHM.L	D3..D5ADD.W D3,#200ADD.W D4,#200	SUB.W	D4,D3		; D4 <-- dx	JUMP,EQ 90$	SWAP.W	D4	SWAP.W	D3	SUB.W	D4,D3		; D4 <-- dy	SWAP.W	D4	SWAP.W	D3	CALL	DRLINE	PUSH.L	D4	LOAD.W	D4,D5	NEG.W	D4	SWAP.W	D4	CLR.W	D4	CALL	DRLINE	POP.L	D4	NEG.W	D4	SWAP.W	D4	NEG.W	D4	SWAP.W	D4	CALL	DRLINE	PUSH.L	D4	LOAD.W	D4,D5	SWAP.W	D4	CLR.W	D4	CALL	DRLINE	POP.L	D4	ASR.W	D4,#1	SUB.W	D3,D4	SWAP.W	D3	SWAP.W	D4	ASR.W	D4,#1	SUB.W	D3,D4	ASR.W	D5,#1	SUB.W	D3,D5	SWAP.W	D3	CALL	DRFILL90$:	POPM.L	D3..D5	RET;----------\\; DRTRANCHE >;==========/; Dessine une tranche de gteau.; in	D0.W	angle de dpart (0..360);	D1.W	angle d'arrive (0..360);	D2.W	mode + flags (BDRT..);	D3.L	centre (y;x);	D4.L	rayons (ry;rx); out	-; mod	D7.WDRTRANCHE:	PUSHM.L	D0..D6	TSET.L	D2:#BNCTDOT	; D2 <-- pas de rz du traitill	TEST.L	D2:#BDRTDA	JUMP',BC 10$	PUSHM.L	D0,D3,D4	LOAD.W	D0,D1	CALL	PCERCLE	LOAD.L	D4,D5	EX.L	D3,D4	SUB.W	D4,D3		; D4 <-- dx	SWAP.W	D4	SWAP.W	D3	SUB.W	D4,D3		; D4 <-- dy	SWAP.W	D4	SWAP.W	D3	CALL	DRLINE		; dessine la droite Da	POPM.L	D0,D3,D410$:	TEST.L	D2:#BDRTDD	JUMP',BC 15$	PUSHM.L	D0,D3,D4	CALL	PCERCLE	LOAD.L	D4,D5	SUB.W	D4,D3		; D4 <-- dx	SWAP.W	D4	SWAP.W	D3	SUB.W	D4,D3		; D4 <-- dy	SWAP.W	D4	SWAP.W	D3	CALL	DRLINE		; dessine la droite Dd	POPM.L	D0,D3,D415$:	TEST.L	D2:#BDRT12	JUMP',BS 30$	TEST.L	D2:#BDRT34	JUMP,BC 90$				; arc dans III et IV =>	COMP.W	D0,#180	JUMP',HS 22$	LOAD.W	D0,#18022$:	COMP.W	D1,#180	JUMP',HS 23$	LOAD.W	D1,#18023$:	COMP.W	D0,D1	JUMP,EQ 90$	PUSH.W	D1	COMP.W	D1,#360	JUMP',LS 25$	LOAD.W	D1,#36025$:	CALL	DRARC	POP.W	D1	COMP.W	D1,#360+180	JUMP,LS 90$	LOAD.W	D0,#360+180	CALL	DRARC	JUMP	90$30$:	TEST.L	D2:#BDRT34	JUMP',BS 40$				; arc dans I et II =>	COMP.W	D0,#180	JUMP',LS 32$	LOAD.W	D0,#36032$:	COMP.W	D1,#360	JUMP',LO 33$	COMP.W	D1,#360+180	JUMP',LS 34$	LOAD.W	D1,#360+180	JUMP'	34$33$:	COMP.W	D1,#180	JUMP',LS 34$	LOAD.W	D1,#18034$:	COMP.W	D0,D1	JUMP,HS 90$	PUSH.W	D1	COMP.W	D0,#360	JUMP',EQ 35$	COMP.W	D1,#180	JUMP',LS 35$	LOAD.W	D1,#18035$:	CALL	DRARC	POP.W	D1	COMP.W	D0,#360	JUMP,EQ 90$	COMP.W	D1,#360	JUMP,LS 90$	LOAD.W	D0,#360	CALL	DRARC	JUMP	90$40$:	CALL	DRARC90$:	POPM.L	D0..D6	RET;--------\\; DRARC   >;========/; Dessine un arc de cercle.; in	D0.W	angle de dpart (0..360);	D1.W	angle d'arrive (0..360);	D2.W	mode;	D3.L	centre (y;x);	D4.L	rayons (ry;rx); out	-; mod	D7.WDRARC:	PUSHM.L	D0..D6	TSET.L	D2:#BNCTDOT	; D2 <-- pas de rz du traitill	CLR.L	D6		; D6 <-- position initiale	LOAD.L	D5,#4*(360/6)	; D5 <-- L*(360/2PI)	DIV.WU	D5,D4	TEST.W	D5	JUMP',NE 20$	INC.W	D520$:	PUSHM.L	D3..D5	CALL	PCERCLE		; D5 <-- nouveau point	LOAD.L	D3,D6	JUMP',NE 30$	LOAD.L	D6,D5	JUMP'	35$30$:	LOAD.L	D4,D5	SUB.W	D4,D3		; D4 <-- dx	SWAP.W	D4	SWAP.W	D3	SUB.W	D4,D3		; D4 <-- dy	SWAP.W	D4	SWAP.W	D3	CALL	DRLINE	LOAD.L	D6,D3		; D6 <-- position suivante35$:	POPM.L	D3..D5	COMP.W	D0,D1	JUMP',HS 90$	ADD.W	D0,D5		; D0 <-- angle suivant	COMP.W	D0,D1	JUMP,LS 20$	LOAD.W	D0,D1	JUMP	20$90$:	POPM.L	D0..D6	RET;--------\\; PCERCLE >;--------/; Calcul les coordonnes d'un point situ sur un cercle.; in	D0.W	angle;	D3.L	centre (y;x);	D4.L	rayons (ry;rx); out	D5.L	point (y;x); mod	D5.L, D7.WPCERCLE:	PUSH.L	D1	CALL	SINUS	SWAP.W	D4	MUL.WA	D1,D4	SWAP.W	D4	ADD.L	D1,#1000/2	DIV.WA	D1,#1000	SWAP.W	D3	ADD.W	D1,D3	SWAP.W	D3	LOAD.W	D5,D1	SWAP.W	D5	CALL	COSINUS	MUL.WA	D1,D4	ADD.L	D1,#1000/2	DIV.WA	D1,#1000	ADD.W	D1,D3	LOAD.W	D5,D1	POP.L	D1	RET;--------\\; COSINUS >;--------/; Calcul rapidement un cosinus.; in	D0.W	angle (0..360); out	D1.W	cosinus (-1000..+1000); mod	D1.L, D7.WCOSINUS:	PUSH.L	D0	AND.L	D0,#H'FFFF	DIV.WU	D0,#360	SWAP.W	D0		; D0 <-- 0..360-1	SUB.W	D0,#90	NEG.W	D0	JUMP',NC 50$	ADD.W	D0,#36050$:	CALL	SINUS	POP.L	D0	RET;--------\\; SINUS   >;--------/; Calcul rapidement un sinus.; in	D0.W	angle (0..360); out	D1.W	sinus (-1000..+1000); mod	D1.L, D7.WSINUS:	PUSHM.L	D0,A3	LOAD.L	A3,#R16"TSINUS	AND.L	D0,#H'FFFF	DIV.WU	D0,#360	SWAP.W	D0		; D0 <-- 0..360-1	COMP.W	D0,#90	JUMP',LS 40$	COMP.W	D0,#180	JUMP',LS 30$	COMP.W	D0,#270	JUMP',LS 20$				; angle 270..360 =>	SUB.W	D0,#360	NEG.W	D0	SL.W	D0,#1	LOAD.W	D1,(A3)+(D0.W)	NEG.W	D1	JUMP'	90$20$:				; angle 180..270 =>	SUB.W	D0,#180	SL.W	D0,#1	LOAD.W	D1,(A3)+(D0.W)	NEG.W	D1	JUMP'	90$30$:				; angle 90..180 =>	SUB.W	D0,#180	NEG.W	D0	SL.W	D0,#1	LOAD.W	D1,(A3)+(D0.W)	JUMP'	90$40$:				; angle 0..90 =>	SL.W	D0,#1	LOAD.W	D1,(A3)+(D0.W);	JUMP'	90$90$:	POPM.L	D0,A3	RETTSINUS:	.W	0,18,35,52,70,87,105,122,139,156	.W	174,191,208,225,242,259,276,292,309,326	.W	342,358,375,391,407,423,438,454,470,485	.W	500,515,530,545,559,574,588,602,616,629	.W	643,656,669,682,695,707,719,731,743,755	.W	766,777,788,799,809,819,829,839,848,857	.W	866,875,883,891,899,906,914,921,927,934	.W	940,946,951,956,961,966,970,974,978,982	.W	985,988,990,993,995,996,998,999,999,1000	.W	1000DRLINE:	.W	LIB,?DRSEG	RETDRFILL:	PUSHM.L	D3,D4	PUSH.L	D3	SUB.W	D3,#10	LOAD.L	D4,#10*2	CALL	DRLINE	POP.L	D3	SWAP.W	D3	SUB.W	D3,#10	SWAP.W	D3	LOAD.W	D4,#10*2	SWAP.W	D4	CLR.W	D4	CALL	DRLINE	POPM.L	D3,D4	RETVAR:	.FILLB	LGVAR,0	.END	START